package com.practice.core.controller;

import com.practice.common.ApiResponse;import com.practice.common.CrudSupport;import com.practice.common.BaseEntity;import com.practice.core.entity.*;import com.practice.core.dao.*;import com.practice.core.service.*;import jakarta.servlet.http.HttpServletRequest;import org.springframework.beans.factory.annotation.Value;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.web.bind.annotation.*;import java.util.*;

@RestController @RequestMapping("/api/auth") class AuthController { @Value("${app.token:panda-iot-demo-token}") String token; final PlatformCoreService service; AuthController(PlatformCoreService service){this.service=service;} @PostMapping("/login") ApiResponse<Map<String,Object>> login(@RequestBody Map<String,String> b, HttpServletRequest r){ return ApiResponse.ok(service.login(b.get("username"), b.get("password"), token, r.getRemoteAddr())); } }
@RestController @RequestMapping("/api/dashboard") class DashboardController { final PlatformCoreService s; DashboardController(PlatformCoreService s){this.s=s;} @GetMapping("/summary") ApiResponse<Map<String,Object>> summary(){return ApiResponse.ok(s.summary());} @GetMapping("/charts") ApiResponse<Map<String,Object>> charts(){return ApiResponse.ok(s.charts());} @GetMapping("/monitor") ApiResponse<Map<String,Object>> monitor(){return ApiResponse.ok(Map.of("cpu",42,"memory",63,"disk",58,"mqtt","running","http","running","jvmThreads",28));} }
@RestController @RequestMapping("/api/telemetry") class TelemetryController { final PlatformCoreService s; TelemetryController(PlatformCoreService s){this.s=s;} @PostMapping("/simulate") ApiResponse<Map<String,Object>> simulate(@RequestBody Map<String,Object> b){return ApiResponse.ok(s.simulate(b));} @PostMapping("/report") ApiResponse<Map<String,Object>> report(@RequestBody Map<String,Object> b){return ApiResponse.ok(s.report(b));} @GetMapping ApiResponse<List<TelemetryData>> list(){return ApiResponse.ok(s.recentTelemetry());} }
@RestController @RequestMapping("/api/alarms") class AlarmController extends CrudController<Alarm>{ final PlatformCoreService s; AlarmController(AlarmDao r, CrudService<Alarm> c, PlatformCoreService s){super(r,c);this.s=s;} @PostMapping("/{id}/handle") ApiResponse<Alarm> handle(@PathVariable Long id,@RequestBody Map<String,Object>b){return ApiResponse.ok(s.handleAlarm(id,b));} @PostMapping("/{id}/close") ApiResponse<Alarm> close(@PathVariable Long id){return ApiResponse.ok(s.handleAlarm(id,Map.of("remark","关闭告警")));} }
@RestController @RequestMapping("/api/tasks") class TaskController extends CrudController<TaskJob>{ final PlatformCoreService s; TaskController(TaskJobDao r, CrudService<TaskJob> c, PlatformCoreService s){super(r,c);this.s=s;} @PostMapping("/{id}/start") ApiResponse<TaskJob> start(@PathVariable Long id){return ApiResponse.ok(s.switchTask(id,true));} @PostMapping("/{id}/stop") ApiResponse<TaskJob> stop(@PathVariable Long id){return ApiResponse.ok(s.switchTask(id,false));} @GetMapping("/logs") ApiResponse<List<TaskLog>> logs(){return ApiResponse.ok(s.taskLogs());} }
@RestController @RequestMapping("/api/network-services") class NetworkServiceController extends CrudController<NetworkService>{ final MqttTelemetrySubscriber mqtt; NetworkServiceController(NetworkServiceDao r, CrudService<NetworkService> c, MqttTelemetrySubscriber mqtt){super(r,c);this.mqtt=mqtt;} @Override @PostMapping("/{id}/toggle") ApiResponse<NetworkService> toggle(@PathVariable Long id){NetworkService old=((NetworkServiceDao)dao).findById(id).orElseThrow();old.status="RUNNING".equals(old.status)?"STOPPED":"RUNNING";NetworkService saved=dao.save(old);if("mqtt-server".equals(saved.code))mqtt.applyNetworkServiceStatus(saved.status);return ApiResponse.ok(saved);} @PostMapping("/{id}/start") ApiResponse<NetworkService> start(@PathVariable Long id){NetworkService saved=service.status(dao,id,"RUNNING");if("mqtt-server".equals(saved.code))mqtt.applyNetworkServiceStatus(saved.status);return ApiResponse.ok(saved);} @PostMapping("/{id}/stop") ApiResponse<NetworkService> stop(@PathVariable Long id){NetworkService saved=service.status(dao,id,"STOPPED");if("mqtt-server".equals(saved.code))mqtt.applyNetworkServiceStatus(saved.status);return ApiResponse.ok(saved);} }
@RestController @RequestMapping("/api/firmwares") class FirmwareController extends CrudController<Firmware>{ FirmwareController(FirmwareDao r, CrudService<Firmware> c){super(r,c);} @PostMapping("/{id}/upgrade") ApiResponse<Firmware> upgrade(@PathVariable Long id,@RequestBody(required=false) Map<String,Object>b){ Firmware f=dao.findById(id).orElseThrow(); f.upgradeStatus= b==null?"UPGRADING":String.valueOf(b.getOrDefault("status","UPGRADING")); f.status=f.upgradeStatus; return ApiResponse.ok(dao.save(f)); } }
@RestController @RequestMapping("/api/ai-agents") class AiAgentController extends CrudController<AiAgent>{ final PlatformCoreService s; AiAgentController(AiAgentDao r, CrudService<AiAgent> c, PlatformCoreService s){super(r,c);this.s=s;} @PostMapping("/chat") ApiResponse<Map<String,Object>> chat(@RequestBody Map<String,Object> b){return ApiResponse.ok(s.aiChat(b));} @PostMapping("/models") ApiResponse<Map<String,Object>> models(@RequestBody(required=false) Map<String,Object> b){return ApiResponse.ok(s.aiModels(b==null?Map.of():b));} }
@RestController @RequestMapping("/api/users") class UserController extends CrudController<SysUser>{ UserController(UserDao r, CrudService<SysUser> c){super(r,c);} @Override @PostMapping ApiResponse<SysUser> create(@RequestBody SysUser body){ if (body.password == null || body.password.isBlank()) body.password="123456"; return ApiResponse.ok(dao.save(body)); } @Override @PutMapping("/{id}") ApiResponse<SysUser> update(@PathVariable Long id,@RequestBody SysUser body){ SysUser old=((UserDao)dao).findById(id).orElseThrow(); if (body.password == null || body.password.isBlank()) body.password=null; return ApiResponse.ok(dao.save(CrudSupport.merge(old,body))); } }
@RestController @RequestMapping("/api/roles") class RoleController extends CrudController<Role>{ RoleController(RoleDao r, CrudService<Role> c){super(r,c);} }
@RestController @RequestMapping("/api/product-categories") class ProductCategoryController extends CrudController<ProductCategory>{ ProductCategoryController(ProductCategoryDao r, CrudService<ProductCategory> c){super(r,c);} @Override @PostMapping ApiResponse<ProductCategory> create(@RequestBody ProductCategory body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<ProductCategory> update(@PathVariable Long id,@RequestBody ProductCategory body){validate(body);return super.update(id,body);} void validate(ProductCategory body){if(blank(body.name))throw new IllegalArgumentException("分类名称不能为空");if(blank(body.code))throw new IllegalArgumentException("分类编码不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/products") class ProductController extends CrudController<Product>{ ProductController(ProductDao r, CrudService<Product> c){super(r,c);} @Override @PostMapping ApiResponse<Product> create(@RequestBody Product body){normalizeRules(body);validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<Product> update(@PathVariable Long id,@RequestBody Product body){normalizeRules(body);validate(body);return super.update(id,body);} void normalizeRules(Product body){if(!blank(body.ruleIds)&&body.ruleId==null){String first=body.ruleIds.split(",")[0].trim();if(!first.isBlank())body.ruleId=Long.valueOf(first);}} void validate(Product body){if(blank(body.name))throw new IllegalArgumentException("产品名称不能为空");if(blank(body.code))throw new IllegalArgumentException("产品编码不能为空");if(body.categoryId==null)throw new IllegalArgumentException("所属分类不能为空");if(body.ruleId==null&&blank(body.ruleIds))throw new IllegalArgumentException("规则链不能为空");if(blank(body.protocol))throw new IllegalArgumentException("接入协议不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/device-groups") class DeviceGroupController extends CrudController<DeviceGroup>{ DeviceGroupController(DeviceGroupDao r, CrudService<DeviceGroup> c){super(r,c);} @Override @PostMapping ApiResponse<DeviceGroup> create(@RequestBody DeviceGroup body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<DeviceGroup> update(@PathVariable Long id,@RequestBody DeviceGroup body){validate(body);return super.update(id,body);} void validate(DeviceGroup body){if(blank(body.name))throw new IllegalArgumentException("分组名称不能为空");if(blank(body.code))throw new IllegalArgumentException("分组编码不能为空");if(blank(body.location))throw new IllegalArgumentException("位置不能为空");if(blank(body.owner))throw new IllegalArgumentException("负责人不能为空");if(body.deviceCount==null)throw new IllegalArgumentException("设备数不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/devices") class DeviceController extends CrudController<Device>{ DeviceController(DeviceDao r, CrudService<Device> c){super(r,c);} @Override @PostMapping ApiResponse<Device> create(@RequestBody Device body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<Device> update(@PathVariable Long id,@RequestBody Device body){validate(body);return super.update(id,body);} void validate(Device body){if(blank(body.name))throw new IllegalArgumentException("设备名称不能为空");if(blank(body.code))throw new IllegalArgumentException("设备编码不能为空");if(body.productId==null)throw new IllegalArgumentException("所属产品不能为空");if(body.groupId==null)throw new IllegalArgumentException("所属分组不能为空");if(blank(body.deviceKey))throw new IllegalArgumentException("设备 Key 不能为空");if(body.temperature==null)throw new IllegalArgumentException("当前温度不能为空");if(blank(body.location))throw new IllegalArgumentException("位置不能为空");if(body.latitude==null)throw new IllegalArgumentException("纬度不能为空");if(body.longitude==null)throw new IllegalArgumentException("经度不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/rules") class RuleController extends CrudController<Rule>{ final AlarmDao alarms; RuleController(RuleDao r, CrudService<Rule> c, AlarmDao alarms){super(r,c);this.alarms=alarms;} @Override @PostMapping ApiResponse<Rule> create(@RequestBody Rule body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<Rule> update(@PathVariable Long id,@RequestBody Rule body){validate(body);Rule old=((RuleDao)dao).findById(id).orElseThrow();Rule saved=service.update(dao,id,body);alarms.findAll().stream().filter(a->Objects.equals(a.ruleId,id)||(a.ruleId==null&&Objects.equals(a.ruleName,old.name))).forEach(a->{a.ruleId=id;a.ruleName=saved.name;a.level=saved.alarmLevel;alarms.save(a);});return ApiResponse.ok(saved);} void validate(Rule body){if(blank(body.name))throw new IllegalArgumentException("规则名称不能为空");if(blank(body.metric))throw new IllegalArgumentException("数据指标不能为空");if(blank(body.operator))throw new IllegalArgumentException("判断条件不能为空");if(body.threshold==null)throw new IllegalArgumentException("阈值不能为空");if(blank(body.alarmLevel))throw new IllegalArgumentException("告警等级不能为空");if(blank(body.action))throw new IllegalArgumentException("触发动作不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/rule-audits") class RuleAuditController extends CrudController<RuleAudit>{ RuleAuditController(RuleAuditDao r, CrudService<RuleAudit> c){super(r,c);} }
@RestController @RequestMapping("/api/scripts") class ScriptController extends CrudController<ParseScript>{ ScriptController(ParseScriptDao r, CrudService<ParseScript> c){super(r,c);} }
@RestController @RequestMapping("/api/operation-logs") class OperationLogController extends CrudController<OperationLog>{ OperationLogController(OperationLogDao r, CrudService<OperationLog> c){super(r,c);} }
@RestController @RequestMapping("/api/login-logs") class LoginLogController extends CrudController<LoginLog>{ LoginLogController(LoginLogDao r, CrudService<LoginLog> c){super(r,c);} }
abstract class CrudController<T extends BaseEntity> { final JpaRepository<T,Long> dao; final CrudService<T> service; CrudController(JpaRepository<T,Long> dao, CrudService<T> service){this.dao=dao;this.service=service;} @GetMapping ApiResponse<List<T>> list(@RequestParam(required=false) String keyword){ return ApiResponse.ok(service.list(dao, keyword)); } @GetMapping("/{id}") ApiResponse<T> get(@PathVariable Long id){ return ApiResponse.ok(service.get(dao,id)); } @PostMapping ApiResponse<T> create(@RequestBody T body){ return ApiResponse.ok(service.create(dao,body)); } @PutMapping("/{id}") ApiResponse<T> update(@PathVariable Long id,@RequestBody T body){ return ApiResponse.ok(service.update(dao,id,body)); } @DeleteMapping("/{id}") ApiResponse<Boolean> delete(@PathVariable Long id){ return ApiResponse.ok(service.delete(dao,id)); } @PostMapping("/{id}/toggle") ApiResponse<T> toggle(@PathVariable Long id){ return ApiResponse.ok(service.toggle(dao,id)); } ApiResponse<T> status(Long id,String status){ return ApiResponse.ok(service.status(dao,id,status)); } }
